/**
 * @psyforge/headless - Type definitions for WebAssembly-based experiment simulation
 */

import type { CompiledExperiment } from '@psyforge/forgescript';

/**
 * Memory metrics for tracking WASM memory usage
 */
export interface MemoryMetrics {
  heapUsed: number;
  heapTotal: number;
  wasmMemoryUsed: number;
  wasmMemoryLimit: number;
  gcCount: number;
  lastGCDuration: number;
}

/**
 * Cognitive model for generating realistic participant responses
 */
export interface CognitiveModel {
  /**
   * Generate reaction time based on stimulus properties
   * @param stimulus The stimulus being responded to
   * @param difficulty Task difficulty (0-1)
   * @returns Reaction time in milliseconds
   */
  reactionTime(stimulus: any, difficulty: number): number;

  /**
   * Determine response accuracy based on stimulus and fatigue
   * @param stimulus The stimulus being responded to
   * @param fatigue Participant fatigue level (0-1)
   * @returns Whether response is correct
   */
  accuracy(stimulus: any, fatigue: number): boolean;

  /**
   * Calculate learning effect over trials
   * @param trialNumber Current trial number
   * @param condition Experimental condition
   * @returns Learning coefficient (0-1)
   */
  learningCurve(trialNumber: number, condition: string): number;
}

/**
 * Pre-built cognitive models for common experimental paradigms
 */
export interface CognitiveModelPresets {
  simpleRT: SimpleRTModel;
  stroopModel: StroopModel;
  nBackModel: NBackModel;
  visualSearchModel: VisualSearchModel;
}

/**
 * Simple reaction time model configuration
 */
export interface SimpleRTModel extends CognitiveModel {
  baseRT: number;
  practiceEffect: number;
  fatigueEffect: number;
  errorRate: number;
  rtVariability: number;
}

/**
 * Stroop task model configuration
 */
export interface StroopModel extends CognitiveModel {
  congruentRT: number;
  incongruentRT: number;
  interferenceDecay: number;
  speedAccuracyTradeoff: number;
  conflictAdaptation: number;
}

/**
 * N-Back task model configuration
 */
export interface NBackModel extends CognitiveModel {
  baseRT: number;
  loadEffect: number;
  hitRate: number;
  falseAlarmRate: number;
  workingMemoryCapacity: number;
}

/**
 * Visual search model configuration
 */
export interface VisualSearchModel extends CognitiveModel {
  targetPresentRT: number;
  targetAbsentRT: number;
  setSize Slope: number;
  popoutEffect: number;
  distractorSimilarity: number;
}

/**
 * Configuration for headless experiment simulation
 */
export interface HeadlessConfig {
  experiment: CompiledExperiment;
  cognitiveModel: CognitiveModel;
  participants: number;
  speedMultiplier: number;
  randomSeed?: number;
  memoryBudget?: number;
  enableTelemetry?: boolean;
}

/**
 * Simulation state at a specific time point
 */
export interface SimulationState {
  virtualTime: number;
  currentTrial: number;
  currentBlock: number;
  stimulusOnScreen: any;
  participantState: ParticipantState;
  performanceMetrics: PerformanceMetrics;
}

/**
 * Individual participant state during simulation
 */
export interface ParticipantState {
  id: string;
  fatigue: number;
  accuracy: number;
  meanRT: number;
  trialsCompleted: number;
  errors: number;
  learningCoefficient: number;
}

/**
 * Performance metrics during simulation
 */
export interface PerformanceMetrics {
  fps: number;
  frameDrops: number;
  memoryUsage: MemoryMetrics;
  cpuUsage: number;
  simulationSpeed: number;
}

/**
 * Results from a complete simulation run
 */
export interface SimulationResults {
  participants: ParticipantResults[];
  aggregateMetrics: AggregateMetrics;
  performanceReport: PerformanceReport;
  dataExport: any[];
}

/**
 * Individual participant results
 */
export interface ParticipantResults {
  participantId: string;
  trials: TrialResult[];
  summary: ParticipantSummary;
}

/**
 * Single trial result
 */
export interface TrialResult {
  trialNumber: number;
  condition: string;
  stimulus: any;
  response: any;
  rt: number;
  correct: boolean;
  timestamp: number;
}

/**
 * Summary statistics for a participant
 */
export interface ParticipantSummary {
  totalTrials: number;
  correctTrials: number;
  accuracy: number;
  meanRT: number;
  sdRT: number;
  medianRT: number;
  minRT: number;
  maxRT: number;
}

/**
 * Aggregate metrics across all participants
 */
export interface AggregateMetrics {
  overallAccuracy: number;
  overallMeanRT: number;
  conditionEffects: Record<string, ConditionMetrics>;
  learningCurve: number[];
  fatigueEffects: number[];
}

/**
 * Metrics for a specific condition
 */
export interface ConditionMetrics {
  accuracy: number;
  meanRT: number;
  sdRT: number;
  n: number;
}

/**
 * Performance report for the simulation
 */
export interface PerformanceReport {
  totalSimulationTime: number;
  virtualTimeElapsed: number;
  speedupFactor: number;
  memoryPeakUsage: number;
  averageFPS: number;
  determinismCheck: boolean;
}

/**
 * Virtual device interface for hardware simulation
 */
export interface VirtualDevice {
  type: 'keyboard' | 'mouse' | 'eyetracker' | 'eeg';
  latency: number;
  precision: number;
  noiseLevel: number;
}

/**
 * Virtual keyboard configuration
 */
export interface VirtualKeyboard extends VirtualDevice {
  type: 'keyboard';
  keyPressVariability: number;
  keyReleaseVariability: number;
  doublePressThreshold: number;
}

/**
 * Virtual mouse configuration
 */
export interface VirtualMouse extends VirtualDevice {
  type: 'mouse';
  movementNoise: number;
  clickVariability: number;
  scrollSensitivity: number;
}

/**
 * Virtual eye tracker configuration
 */
export interface VirtualEyeTracker extends VirtualDevice {
  type: 'eyetracker';
  samplingRate: number;
  spatialAccuracy: number;
  saccadeThreshold: number;
  fixationMinDuration: number;
  blinkDuration: number;
}

/**
 * Virtual EEG configuration
 */
export interface VirtualEEG extends VirtualDevice {
  type: 'eeg';
  channels: number;
  samplingRate: number;
  noiseFloor: number;
  artifactProbability: number;
}

/**
 * Export configuration for simulation data
 */
export interface ExportConfig {
  format: 'json' | 'csv' | 'bids';
  includeRawData: boolean;
  includeSummaryStats: boolean;
  includePerformanceMetrics: boolean;
  compression: boolean;
}

