/**
 * @psyforge/headless - WebAssembly-based experiment runner for simulation
 */

import type { CompiledExperiment } from '@psyforge/forgescript';
import { PrecisionClock } from '@psyforge/timing';
import type {
  HeadlessConfig,
  SimulationState,
  SimulationResults,
  MemoryMetrics,
  ParticipantState,
  PerformanceMetrics,
  TrialResult,
  ParticipantResults,
  AggregateMetrics,
  PerformanceReport
} from './types';

/**
 * WebAssembly-based headless experiment runner
 * Provides deterministic simulation with configurable speed
 */
export class HeadlessRunner {
  private config: HeadlessConfig;
  private clock: PrecisionClock;
  private virtualTime: number = 0;
  private realStartTime: number = 0;
  private participants: Map<string, ParticipantState> = new Map();
  private results: Map<string, TrialResult[]> = new Map();
  private memoryMetrics: MemoryMetrics = {
    heapUsed: 0,
    heapTotal: 0,
    wasmMemoryUsed: 0,
    wasmMemoryLimit: 100 * 1024 * 1024, // 100MB default
    gcCount: 0,
    lastGCDuration: 0
  };
  private performanceMetrics: PerformanceMetrics = {
    fps: 0,
    frameDrops: 0,
    memoryUsage: this.memoryMetrics,
    cpuUsage: 0,
    simulationSpeed: 1
  };
  private rng: () => number;

  constructor(config: HeadlessConfig) {
    this.config = config;
    this.clock = new PrecisionClock();

    // Initialize deterministic random number generator
    this.rng = this.createRNG(config.randomSeed);

    // Initialize participants
    this.initializeParticipants();

    // Set memory budget if specified
    if (config.memoryBudget) {
      this.memoryMetrics.wasmMemoryLimit = config.memoryBudget;
    }
  }

  /**
   * Run complete experiment simulation
   */
  async simulate(): Promise<SimulationResults> {
    this.realStartTime = performance.now();

    // Calculate total experiment duration
    const totalDuration = this.calculateExperimentDuration();

    // Run simulation loop
    while (this.virtualTime < totalDuration) {
      await this.simulateFrame();

      // Check memory usage
      if (this.memoryMetrics.wasmMemoryUsed > this.memoryMetrics.wasmMemoryLimit) {
        throw new Error(`Memory budget exceeded: ${this.memoryMetrics.wasmMemoryUsed} > ${this.memoryMetrics.wasmMemoryLimit}`);
      }
    }

    // Compile results
    return this.compileResults();
  }

  /**
   * Run simulation until specific time point
   */
  async simulateUntil(targetTime: number): Promise<SimulationState> {
    while (this.virtualTime < targetTime) {
      await this.simulateFrame();
    }

    return this.getCurrentState();
  }

  /**
   * Simulate a single frame
   */
  private async simulateFrame(): Promise<void> {
    const frameStart = performance.now();

    // Calculate virtual time increment based on speed multiplier
    const virtualIncrement = (16.67 / 1000) * this.config.speedMultiplier; // 60fps base
    this.virtualTime += virtualIncrement;

    // Process experiment logic for current time
    await this.processExperimentFrame();

    // Update performance metrics
    const frameEnd = performance.now();
    const frameDuration = frameEnd - frameStart;
    this.updatePerformanceMetrics(frameDuration);

    // Yield to event loop periodically for non-blocking simulation
    if (Math.random() < 0.01) { // 1% chance
      await new Promise(resolve => setImmediate(resolve));
    }
  }

  /**
   * Process experiment logic for current frame
   */
  private async processExperimentFrame(): Promise<void> {
    // This would integrate with the ForgeScript runtime
    // For now, simulate basic experiment flow

    for (const [participantId, state] of this.participants) {
      // Check if participant should respond at this time
      const shouldRespond = this.checkResponseWindow(state);

      if (shouldRespond) {
        const response = this.generateResponse(state);
        this.recordResponse(participantId, response);
        this.updateParticipantState(state, response);
      }
    }
  }

  /**
   * Generate participant response based on cognitive model
   */
  private generateResponse(participant: ParticipantState): TrialResult {
    // Get current stimulus from experiment
    const stimulus = this.getCurrentStimulus();

    // Calculate reaction time using cognitive model
    const difficulty = this.calculateDifficulty(stimulus);
    const rt = this.config.cognitiveModel.reactionTime(stimulus, difficulty);

    // Add noise and fatigue effects
    const noisyRT = rt * (1 + (this.rng() - 0.5) * 0.1); // ±5% noise
    const finalRT = noisyRT * (1 + participant.fatigue * 0.2); // Up to 20% slower when fatigued

    // Determine accuracy
    const correct = this.config.cognitiveModel.accuracy(stimulus, participant.fatigue);

    return {
      trialNumber: participant.trialsCompleted + 1,
      condition: stimulus.condition || 'default',
      stimulus,
      response: { key: this.selectResponseKey(stimulus, correct) },
      rt: Math.round(finalRT),
      correct,
      timestamp: this.virtualTime
    };
  }

  /**
   * Get current state of simulation
   */
  private getCurrentState(): SimulationState {
    const participantStates = Array.from(this.participants.values());
    const averageState = this.calculateAverageParticipantState(participantStates);

    return {
      virtualTime: this.virtualTime,
      currentTrial: averageState.trialsCompleted,
      currentBlock: Math.floor(averageState.trialsCompleted / 20), // Assuming 20 trials per block
      stimulusOnScreen: this.getCurrentStimulus(),
      participantState: averageState,
      performanceMetrics: { ...this.performanceMetrics }
    };
  }

  /**
   * Compile final results
   */
  private compileResults(): SimulationResults {
    const participants: ParticipantResults[] = [];

    for (const [participantId, trials] of this.results) {
      const summary = this.calculateParticipantSummary(trials);
      participants.push({
        participantId,
        trials,
        summary
      });
    }

    const aggregateMetrics = this.calculateAggregateMetrics(participants);
    const performanceReport = this.generatePerformanceReport();

    return {
      participants,
      aggregateMetrics,
      performanceReport,
      dataExport: this.exportData(participants)
    };
  }

  /**
   * Calculate participant summary statistics
   */
  private calculateParticipantSummary(trials: TrialResult[]): any {
    const correctTrials = trials.filter(t => t.correct).length;
    const rts = trials.map(t => t.rt);

    return {
      totalTrials: trials.length,
      correctTrials,
      accuracy: correctTrials / trials.length,
      meanRT: this.mean(rts),
      sdRT: this.standardDeviation(rts),
      medianRT: this.median(rts),
      minRT: Math.min(...rts),
      maxRT: Math.max(...rts)
    };
  }

  /**
   * Calculate aggregate metrics across participants
   */
  private calculateAggregateMetrics(participants: ParticipantResults[]): AggregateMetrics {
    const allTrials = participants.flatMap(p => p.trials);
    const conditions = new Set(allTrials.map(t => t.condition));

    const conditionEffects: Record<string, any> = {};
    for (const condition of conditions) {
      const conditionTrials = allTrials.filter(t => t.condition === condition);
      conditionEffects[condition] = {
        accuracy: conditionTrials.filter(t => t.correct).length / conditionTrials.length,
        meanRT: this.mean(conditionTrials.map(t => t.rt)),
        sdRT: this.standardDeviation(conditionTrials.map(t => t.rt)),
        n: conditionTrials.length
      };
    }

    return {
      overallAccuracy: allTrials.filter(t => t.correct).length / allTrials.length,
      overallMeanRT: this.mean(allTrials.map(t => t.rt)),
      conditionEffects,
      learningCurve: this.calculateLearningCurve(allTrials),
      fatigueEffects: this.calculateFatigueEffects(participants)
    };
  }

  /**
   * Generate performance report
   */
  private generatePerformanceReport(): PerformanceReport {
    const realDuration = performance.now() - this.realStartTime;
    const virtualDuration = this.virtualTime * 1000; // Convert to ms

    return {
      totalSimulationTime: realDuration,
      virtualTimeElapsed: virtualDuration,
      speedupFactor: virtualDuration / realDuration,
      memoryPeakUsage: this.memoryMetrics.wasmMemoryUsed,
      averageFPS: this.performanceMetrics.fps,
      determinismCheck: true // Would verify reproducibility with same seed
    };
  }

  /**
   * Initialize participant states
   */
  private initializeParticipants(): void {
    for (let i = 0; i < this.config.participants; i++) {
      const id = `P${String(i + 1).padStart(3, '0')}`;
      this.participants.set(id, {
        id,
        fatigue: 0,
        accuracy: 1,
        meanRT: 400,
        trialsCompleted: 0,
        errors: 0,
        learningCoefficient: 1
      });
      this.results.set(id, []);
    }
  }

  /**
   * Create deterministic random number generator
   */
  private createRNG(seed?: number): () => number {
    let s = seed ?? Date.now();
    return () => {
      s = (s * 1664525 + 1013904223) % 4294967296;
      return s / 4294967296;
    };
  }

  /**
   * Update performance metrics
   */
  private updatePerformanceMetrics(frameDuration: number): void {
    this.performanceMetrics.fps = 1000 / frameDuration;
    this.performanceMetrics.simulationSpeed = this.config.speedMultiplier;

    // Update memory metrics (would use actual WASM memory in production)
    if (typeof process !== 'undefined' && process.memoryUsage) {
      const usage = process.memoryUsage();
      this.memoryMetrics.heapUsed = usage.heapUsed;
      this.memoryMetrics.heapTotal = usage.heapTotal;
      this.memoryMetrics.wasmMemoryUsed = usage.heapUsed; // Placeholder
    }
  }

  /**
   * Get memory usage metrics
   */
  getMemoryUsage(): MemoryMetrics {
    return { ...this.memoryMetrics };
  }

  // Helper methods
  private mean(values: number[]): number {
    return values.reduce((a, b) => a + b, 0) / values.length;
  }

  private standardDeviation(values: number[]): number {
    const avg = this.mean(values);
    const squareDiffs = values.map(value => Math.pow(value - avg, 2));
    return Math.sqrt(this.mean(squareDiffs));
  }

  private median(values: number[]): number {
    const sorted = [...values].sort((a, b) => a - b);
    const mid = Math.floor(sorted.length / 2);
    return sorted.length % 2 ? sorted[mid] : (sorted[mid - 1] + sorted[mid]) / 2;
  }

  // Placeholder methods that would integrate with ForgeScript runtime
  private calculateExperimentDuration(): number {
    // Would calculate from experiment structure
    return 300; // 5 minutes default
  }

  private getCurrentStimulus(): any {
    // Would get from experiment timeline
    return { type: 'text', content: 'TEST', condition: 'congruent' };
  }

  private checkResponseWindow(participant: ParticipantState): boolean {
    // Would check experiment timeline
    return Math.random() < 0.01; // 1% chance per frame for testing
  }

  private calculateDifficulty(stimulus: any): number {
    // Would calculate from stimulus properties
    return stimulus.condition === 'incongruent' ? 0.8 : 0.2;
  }

  private selectResponseKey(stimulus: any, correct: boolean): string {
    // Would determine based on stimulus and correctness
    return correct ? 'ArrowLeft' : 'ArrowRight';
  }

  private recordResponse(participantId: string, response: TrialResult): void {
    const trials = this.results.get(participantId) || [];
    trials.push(response);
    this.results.set(participantId, trials);
  }

  private updateParticipantState(state: ParticipantState, response: TrialResult): void {
    state.trialsCompleted++;
    if (!response.correct) state.errors++;

    // Update fatigue (increases over time)
    state.fatigue = Math.min(1, state.fatigue + 0.001);

    // Update learning coefficient
    const learningRate = this.config.cognitiveModel.learningCurve(
      state.trialsCompleted,
      response.condition
    );
    state.learningCoefficient *= learningRate;

    // Update running accuracy
    state.accuracy = (state.trialsCompleted - state.errors) / state.trialsCompleted;
  }

  private calculateAverageParticipantState(states: ParticipantState[]): ParticipantState {
    const avg = {
      id: 'average',
      fatigue: this.mean(states.map(s => s.fatigue)),
      accuracy: this.mean(states.map(s => s.accuracy)),
      meanRT: this.mean(states.map(s => s.meanRT)),
      trialsCompleted: Math.round(this.mean(states.map(s => s.trialsCompleted))),
      errors: Math.round(this.mean(states.map(s => s.errors))),
      learningCoefficient: this.mean(states.map(s => s.learningCoefficient))
    };
    return avg;
  }

  private calculateLearningCurve(trials: TrialResult[]): number[] {
    // Group trials by trial number and calculate accuracy
    const maxTrial = Math.max(...trials.map(t => t.trialNumber));
    const curve: number[] = [];

    for (let i = 1; i <= maxTrial; i++) {
      const trialsAtN = trials.filter(t => t.trialNumber === i);
      if (trialsAtN.length > 0) {
        curve.push(trialsAtN.filter(t => t.correct).length / trialsAtN.length);
      }
    }

    return curve;
  }

  private calculateFatigueEffects(participants: ParticipantResults[]): number[] {
    // Calculate RT increase over time as fatigue indicator
    const effects: number[] = [];
    const blockSize = 20;

    for (const participant of participants) {
      const blocks = Math.floor(participant.trials.length / blockSize);
      for (let i = 0; i < blocks; i++) {
        const blockTrials = participant.trials.slice(i * blockSize, (i + 1) * blockSize);
        const meanRT = this.mean(blockTrials.map(t => t.rt));
        effects.push(meanRT);
      }
    }

    return effects;
  }

  private exportData(participants: ParticipantResults[]): any[] {
    // Export in BIDS-compatible format
    const data: any[] = [];

    for (const participant of participants) {
      for (const trial of participant.trials) {
        data.push({
          participant_id: participant.participantId,
          trial: trial.trialNumber,
          condition: trial.condition,
          rt: trial.rt,
          accuracy: trial.correct ? 1 : 0,
          onset: trial.timestamp,
          duration: trial.rt / 1000
        });
      }
    }

    return data;
  }
}

