import type {
  VirtualDevice,
  VirtualKeyboard,
  VirtualMouse,
  VirtualEyeTracker,
  VirtualEEG
} from './types';

/**
 * Base virtual device implementation
 */
abstract class BaseVirtualDevice implements VirtualDevice {
  type: 'keyboard' | 'mouse' | 'eyetracker' | 'eeg';
  latency: number;
  precision: number;
  noiseLevel: number;

  constructor(
    type: VirtualDevice['type'],
    latency: number = 5,
    precision: number = 1,
    noiseLevel: number = 0.05
  ) {
    this.type = type;
    this.latency = latency;
    this.precision = precision;
    this.noiseLevel = noiseLevel;
  }

  /**
   * Add noise to a measurement
   */
  protected addNoise(value: number): number {
    const noise = (Math.random() - 0.5) * 2 * this.noiseLevel;
    return value * (1 + noise);
  }

  /**
   * Simulate device latency
   */
  protected simulateLatency(): number {
    // Latency follows gamma distribution
    const shape = 2; // Shape parameter
    const scale = this.latency / shape; // Scale to achieve mean = latency

    let sum = 0;
    for (let i = 0; i < shape; i++) {
      sum += -Math.log(Math.random()) * scale;
    }

    return Math.max(0, sum);
  }
}

