  simulateSmoothPursuit(
    path: Array<{ x: number; y: number; timestamp: number }>
  ): Array<{ x: number; y: number; pupilSize: number; timestamp: number; event?: string }> {
    const samples: Array<any> = [];

    for (let i = 0; i < path.length; i++) {
      const point = path[i];

      // Smooth pursuit has small lag and overshoot
      const lag = 50; // ms
      const overshoot = 0.05;

      let x = point.x;
      let y = point.y;

      if (i > 0) {
        const prevPoint = path[i - 1];
        const velocityX = (point.x - prevPoint.x) / (point.timestamp - prevPoint.timestamp);
        const velocityY = (point.y - prevPoint.y) / (point.timestamp - prevPoint.timestamp);

        x += velocityX * lag + velocityX * overshoot;
        y += velocityY * lag + velocityY * overshoot;
      }

      samples.push({
        x: this.addSpatialNoise(x),
        y: this.addSpatialNoise(y),
        pupilSize: this.pupilSize,
        timestamp: point.timestamp + this.simulateLatency(),
        event: i === 0 ? 'smooth_pursuit_start' : undefined
      });
    }

    return samples;
  }

  private calculateSaccadeDuration(x1: number, y1: number, x2: number, y2: number): number {
    const distance = Math.sqrt(Math.pow(x2 - x1, 2) + Math.pow(y2 - y1, 2));
    // Main sequence: duration = 21 + 2.2 * amplitude (in degrees)
    return 21 + 2.2 * distance;
  }

  private addSpatialNoise(coord: number): number {
    const noiseInDegrees = (Math.random() - 0.5) * this.spatialAccuracy;
    return coord + noiseInDegrees;
  }

  private simulateFixationDrift(): { x: number; y: number } {
    // Random walk for fixation drift
    return {
      x: (Math.random() - 0.5) * 0.1,
      y: (Math.random() - 0.5) * 0.1
    };
  }
}

/**
 * Virtual EEG device
 */
export class VirtualEEGDevice extends BaseVirtualDevice implements VirtualEEG {
  channels: number;
  samplingRate: number;
  noiseFloor: number;
  artifactProbability: number;
  private channelOffsets: number[] = [];
  private time: number = 0;

  constructor(config?: Partial<VirtualEEG>) {
    super('eeg', config?.latency || 20, config?.precision || 0.1, config?.noiseLevel || 0.2);
    this.channels = config?.channels || 32;
    this.samplingRate = config?.samplingRate || 500; // Hz
    this.noiseFloor = config?.noiseFloor || 5; // μV
    this.artifactProbability = config?.artifactProbability || 0.01;

    // Initialize channel offsets
    for (let i = 0; i < this.channels; i++) {
      this.channelOffsets.push((Math.random() - 0.5) * 10);
    }
  }

  /**
   * Generate synthetic EEG signal
   */
  generateSignal(duration: number, eventTimestamps: number[] = []): Array<{
    timestamp: number;
    data: number[];
    events: string[];
  }> {
    const samples: Array<any> = [];
    const sampleInterval = 1000 / this.samplingRate;
    const numSamples = Math.ceil(duration / sampleInterval);

    for (let i = 0; i < numSamples; i++) {
      const timestamp = i * sampleInterval;
      const data: number[] = [];
      const events: string[] = [];

      // Check for events at this timestamp
      for (const eventTime of eventTimestamps) {
        if (Math.abs(timestamp - eventTime) < sampleInterval / 2) {
          events.push('stimulus');
        }
      }

      // Generate signal for each channel
      for (let ch = 0; ch < this.channels; ch++) {
        let signal = 0;

        // Alpha rhythm (8-12 Hz)
        signal += 10 * Math.sin(2 * Math.PI * 10 * timestamp / 1000 + this.channelOffsets[ch]);

        // Beta rhythm (13-30 Hz)
        signal += 5 * Math.sin(2 * Math.PI * 20 * timestamp / 1000 + this.channelOffsets[ch] * 2);

        // Gamma rhythm (30-100 Hz)
        signal += 2 * Math.sin(2 * Math.PI * 40 * timestamp / 1000 + this.channelOffsets[ch] * 3);

        // Event-related potential (if event occurred)
        if (events.length > 0) {
          const erpLatency = timestamp - eventTimestamps[eventTimestamps.indexOf(timestamp)];
          if (erpLatency >= 0 && erpLatency < 600) {
            // P300-like component
            if (erpLatency > 250 && erpLatency < 500) {
              signal += 15 * Math.exp(-(Math.pow(erpLatency - 300, 2) / 10000));
            }
            // N100-like component
            if (erpLatency > 80 && erpLatency < 150) {
              signal -= 8 * Math.exp(-(Math.pow(erpLatency - 100, 2) / 400));
            }
          }
        }

        // Add noise
        signal += this.gaussianNoise() * this.noiseFloor;

        // Add artifacts occasionally
        if (Math.random() < this.artifactProbability) {
          signal += (Math.random() - 0.5) * 100; // Large artifact
        }

        data.push(Math.round(signal * this.precision) / this.precision);
      }

      samples.push({
        timestamp: timestamp + this.simulateLatency(),
        data,
        events
      });
    }

    return samples;
  }

  /**
   * Generate specific ERP component
   */
  generateERP(
    component: 'N100' | 'P300' | 'N400' | 'MMN',
    amplitude: number = 10
  ): Array<{ timestamp: number; amplitude: number }> {
    const erp: Array<any> = [];
    const sampleInterval = 1000 / this.samplingRate;

    let peakLatency: number;
    let duration: number;
    let polarity: number;

    switch (component) {
      case 'N100':
        peakLatency = 100;
        duration = 100;
        polarity = -1;
        break;
      case 'P300':
        peakLatency = 300;
        duration = 200;
        polarity = 1;
        break;
      case 'N400':
        peakLatency = 400;
        duration = 200;
        polarity = -1;
        break;
      case 'MMN':
        peakLatency = 150;
        duration = 100;
        polarity = -1;
        break;
    }

    for (let t = 0; t < 1000; t += sampleInterval) {
      let value = 0;

      if (t > peakLatency - duration / 2 && t < peakLatency + duration / 2) {
        // Gaussian-shaped component
        value = amplitude * polarity * Math.exp(-(Math.pow(t - peakLatency, 2) / (2 * Math.pow(duration / 4, 2))));
      }

      erp.push({
        timestamp: t,
        amplitude: value + this.gaussianNoise() * this.noiseFloor * 0.1
      });
    }

    return erp;
  }

  private gaussianNoise(): number {
    const u1 = Math.random();
    const u2 = Math.random();
    return Math.sqrt(-2 * Math.log(u1)) * Math.cos(2 * Math.PI * u2);
  }
}

/**
 * Factory for creating virtual devices
 */
export class VirtualDeviceFactory {
  static createKeyboard(config?: Partial<VirtualKeyboard>): VirtualKeyboardDevice {
    return new VirtualKeyboardDevice(config);
  }

  static createMouse(config?: Partial<VirtualMouse>): VirtualMouseDevice {
    return new VirtualMouseDevice(config);
  }

  static createEyeTracker(config?: Partial<VirtualEyeTracker>): VirtualEyeTrackerDevice {
    return new VirtualEyeTrackerDevice(config);
  }

  static createEEG(config?: Partial<VirtualEEG>): VirtualEEGDevice {
    return new VirtualEEGDevice(config);
  }
}

