/**
 * @psyforge/headless - Virtual device implementations for hardware simulation
 */

import type {
  VirtualDevice,
  VirtualKeyboard,
  VirtualMouse,
  VirtualEyeTracker,
  VirtualEEG
} from './types';

/**
 * Base virtual device implementation
 */
abstract class BaseVirtualDevice implements VirtualDevice {
  type: 'keyboard' | 'mouse' | 'eyetracker' | 'eeg';
  latency: number;
  precision: number;
  noiseLevel: number;

  constructor(
    type: VirtualDevice['type'],
    latency: number = 5,
    precision: number = 1,
    noiseLevel: number = 0.05
  ) {
    this.type = type;
    this.latency = latency;
    this.precision = precision;
    this.noiseLevel = noiseLevel;
  }

  /**
   * Add noise to a measurement
   */
  protected addNoise(value: number): number {
    const noise = (Math.random() - 0.5) * 2 * this.noiseLevel;
    return value * (1 + noise);
  }

  /**
   * Simulate device latency
   */
  protected simulateLatency(): number {
    // Latency follows gamma distribution
    const shape = 2; // Shape parameter
    const scale = this.latency / shape; // Scale to achieve mean = latency

    let sum = 0;
    for (let i = 0; i < shape; i++) {
      sum += -Math.log(Math.random()) * scale;
    }

    return Math.max(0, sum);
  }
}

/**
 * Virtual keyboard device
 */
export class VirtualKeyboardDevice extends BaseVirtualDevice implements VirtualKeyboard {
  keyPressVariability: number;
  keyReleaseVariability: number;
  doublePressThreshold: number;
  private keyStates: Map<string, boolean> = new Map();
  private lastKeyPress: Map<string, number> = new Map();

  constructor(config?: Partial<VirtualKeyboard>) {
    super('keyboard', config?.latency || 5, config?.precision || 1, config?.noiseLevel || 0.02);
    this.keyPressVariability = config?.keyPressVariability || 10;
    this.keyReleaseVariability = config?.keyReleaseVariability || 15;
    this.doublePressThreshold = config?.doublePressThreshold || 50;
  }

  /**
   * Simulate key press event
   */
  simulateKeyPress(key: string, timestamp: number): { key: string; timestamp: number; latency: number } {
    const latency = this.simulateLatency();
    const variability = this.addNoise(this.keyPressVariability);

    // Check for double press
    const lastPress = this.lastKeyPress.get(key) || 0;
    if (timestamp - lastPress < this.doublePressThreshold) {
      // Ignore double press
      return { key: '', timestamp: 0, latency: 0 };
    }

    this.keyStates.set(key, true);
    this.lastKeyPress.set(key, timestamp);

    return {
      key,
      timestamp: timestamp + latency + variability,
      latency: latency + variability
    };
  }

  /**
   * Simulate key release event
   */
  simulateKeyRelease(key: string, timestamp: number): { key: string; timestamp: number; duration: number } {
    const latency = this.simulateLatency();
    const variability = this.addNoise(this.keyReleaseVariability);
    const pressTime = this.lastKeyPress.get(key) || timestamp;

    this.keyStates.set(key, false);

    return {
      key,
      timestamp: timestamp + latency + variability,
      duration: timestamp - pressTime
    };
  }

  /**
   * Get current key states
   */
  getKeyStates(): Map<string, boolean> {
    return new Map(this.keyStates);
  }
}

/**
 * Virtual mouse device
 */
export class VirtualMouseDevice extends BaseVirtualDevice implements VirtualMouse {
  movementNoise: number;
  clickVariability: number;
  scrollSensitivity: number;
  private position: { x: number; y: number } = { x: 0, y: 0 };
  private buttonStates: Map<number, boolean> = new Map();

  constructor(config?: Partial<VirtualMouse>) {
    super('mouse', config?.latency || 3, config?.precision || 2, config?.noiseLevel || 0.03);
    this.movementNoise = config?.movementNoise || 2;
    this.clickVariability = config?.clickVariability || 5;
    this.scrollSensitivity = config?.scrollSensitivity || 3;
  }

  /**
   * Simulate mouse movement
   */
  simulateMovement(targetX: number, targetY: number, duration: number): Array<{ x: number; y: number; timestamp: number }> {
    const steps = Math.ceil(duration / 16.67); // 60 FPS
    const path: Array<{ x: number; y: number; timestamp: number }> = [];

    const startX = this.position.x;
    const startY = this.position.y;

    for (let i = 0; i <= steps; i++) {
      const t = i / steps;
      // Bezier curve for smooth movement
      const eased = this.easeInOutCubic(t);

      let x = startX + (targetX - startX) * eased;
      let y = startY + (targetY - startY) * eased;

      // Add movement noise
      x += (Math.random() - 0.5) * this.movementNoise;
      y += (Math.random() - 0.5) * this.movementNoise;

      path.push({
        x: Math.round(x * this.precision) / this.precision,
        y: Math.round(y * this.precision) / this.precision,
        timestamp: (i * 16.67) + this.simulateLatency()
      });
    }

    this.position = { x: targetX, y: targetY };
    return path;
  }

  /**
   * Simulate mouse click
   */
  simulateClick(button: number, timestamp: number): { button: number; timestamp: number; latency: number } {
    const latency = this.simulateLatency();
    const variability = this.addNoise(this.clickVariability);

    this.buttonStates.set(button, true);

    // Simulate release after short duration
    setTimeout(() => {
      this.buttonStates.set(button, false);
    }, 50 + variability);

    return {
      button,
      timestamp: timestamp + latency + variability,
      latency: latency + variability
    };
  }

  /**
   * Simulate scroll event
   */
  simulateScroll(deltaY: number, timestamp: number): { deltaY: number; timestamp: number } {
    const latency = this.simulateLatency();
    const adjustedDelta = deltaY * this.scrollSensitivity;

    return {
      deltaY: this.addNoise(adjustedDelta),
      timestamp: timestamp + latency
    };
  }

  private easeInOutCubic(t: number): number {
    return t < 0.5 ? 4 * t * t * t : 1 - Math.pow(-2 * t + 2, 3) / 2;
  }
}

/**
 * Virtual eye tracker device
 */
export class VirtualEyeTrackerDevice extends BaseVirtualDevice implements VirtualEyeTracker {
  samplingRate: number;
  spatialAccuracy: number;
  saccadeThreshold: number;
  fixationMinDuration: number;
  blinkDuration: number;
  private gazePosition: { x: number; y: number } = { x: 0, y: 0 };
  private pupilSize: number = 3.5; // mm
  private isBlinking: boolean = false;
  private lastSaccadeTime: number = 0;

  constructor(config?: Partial<VirtualEyeTracker>) {
    super('eyetracker', config?.latency || 10, config?.precision || 0.5, config?.noiseLevel || 0.1);
    this.samplingRate = config?.samplingRate || 250; // Hz
    this.spatialAccuracy = config?.spatialAccuracy || 0.5; // degrees
    this.saccadeThreshold = config?.saccadeThreshold || 30; // degrees/second
    this.fixationMinDuration = config?.fixationMinDuration || 100; // ms
    this.blinkDuration = config?.blinkDuration || 150; // ms
  }

  /**
   * Simulate gaze path between fixations
   */
  simulateGazePath(
    startX: number,
    startY: number,
    endX: number,
    endY: number,
    includesSaccade: boolean = true
  ): Array<{ x: number; y: number; pupilSize: number; timestamp: number; event?: string }> {
    const samples: Array<any> = [];
    const sampleInterval = 1000 / this.samplingRate;

    if (includesSaccade) {
      // Simulate saccade
      const saccadeDuration = this.calculateSaccadeDuration(startX, startY, endX, endY);
      const saccadeSamples = Math.ceil(saccadeDuration / sampleInterval);

      for (let i = 0; i < saccadeSamples; i++) {
        const t = i / saccadeSamples;
        const x = startX + (endX - startX) * t;
        const y = startY + (endY - startY) * t;

        samples.push({
          x: this.addSpatialNoise(x),
          y: this.addSpatialNoise(y),
          pupilSize: this.pupilSize * 1.1, // Pupil dilates during saccade
          timestamp: i * sampleInterval,
          event: i === 0 ? 'saccade_start' : (i === saccadeSamples - 1 ? 'saccade_end' : undefined)
        });
      }

      this.lastSaccadeTime = Date.now();
    }

    // Simulate fixation
    const fixationDuration = this.fixationMinDuration + Math.random() * 200;
    const fixationSamples = Math.ceil(fixationDuration / sampleInterval);

    for (let i = 0; i < fixationSamples; i++) {
      // Microsaccades and drift during fixation
      const drift = this.simulateFixationDrift();

      samples.push({
        x: this.addSpatialNoise(endX + drift.x),
        y: this.addSpatialNoise(endY + drift.y),
        pupilSize: this.pupilSize + (Math.random() - 0.5) * 0.2,
        timestamp: (saccadeSamples + i) * sampleInterval + this.simulateLatency(),
        event: i === 0 ? 'fixation_start' : undefined
      });
    }

    this.gazePosition = { x: endX, y: endY };
    return samples;
  }

  /**
   * Simulate blink
   */
  simulateBlink(timestamp: number): Array<{ x: number; y: number; pupilSize: number; timestamp: number; event: string }> {
    const samples: Array<any> = [];
    const sampleInterval = 1000 / this.samplingRate;
    const blinkSamples = Math.ceil(this.blinkDuration / sampleInterval);

    this.isBlinking = true;

    for (let i = 0; i < blinkSamples; i++) {
      samples.push({
        x: NaN, // No gaze data during blink
        y: NaN,
        pupilSize: 0,
        timestamp: timestamp + i * sampleInterval,
        event: i === 0 ? 'blink_start' : (i === blinkSamples - 1 ? 'blink_end' : undefined)
      });
    }

    this.isBlinking = false;
    return samples;
  }

  /**
   * Simulate smooth pursuit
   */
  simulateSmoothPursuit(
    path: Array<{ x: number; y: number; timestamp: number }>
  ): Array<{ x: number; y: number; pupilSize: number; timestamp: number; event?: string }> {
    const samples: Array<any> = [];

    for (let i = 0; i < path.length; i++) {
      const point = path[i];

      // Smooth pursuit has small lag and overshoot
      const lag = 50; // ms
      const overshoot = 0.05;

      let x = point.x;
      let y = point.y;

      if (i > 0) {
        const prevPoint = path[i - 1];
        const velocityX = (point.x - prevPoint.x) / (point.timestamp - prevPoint.timestamp);
        const velocityY = (point.y - prevPoint.y) / (point.timestamp - prevPoint.timestamp);

        x += velocityX * lag + velocityX * overshoot;
        y += velocityY * lag + velocityY * overshoot;
      }

      samples.push({
        x: this.addSpatialNoise(x),
        y: this.addSpatialNoise(y),
        pupilSize: this.pupilSize,
        timestamp: point.timestamp + this.simulateLatency(),
        event: i === 0 ? 'smooth_pursuit_start' : undefined
      });
    }

    return samples;
  }

  private calculateSaccadeDuration(x1: number, y1: number, x2: number, y2: number): number {
    const distance = Math.sqrt(Math.pow(x2 - x1, 2) + Math.pow(y2 - y1, 2));
    // Main sequence: duration = 21 + 2.2 * amplitude (in degrees)
    return 21 + 2.2 * distance;
  }

  private addSpatialNoise(coord: number): number {
    const noiseInDegrees = (Math.random() - 0.5) * this.spatialAccuracy;
    return coord + noiseInDegrees;
  }

  private simulateFixationDrift(): { x: number; y: number } {
    // Random walk for fixation drift
    return {
      x: (Math.random() - 0.5) * 0.1,
      y: (Math.random() - 0.5) * 0.1
    };
  }
}

/**
 * Virtual EEG device
 */
export class VirtualEEGDevice extends BaseVirtualDevice implements VirtualEEG {
  channels: number;
  samplingRate: number;
  noiseFloor: number;
  artifactProbability: number;
  private channelOffsets: number[] = [];
  private time: number = 0;

  constructor(config?: Partial<VirtualEEG>) {
    super('eeg', config?.latency || 20, config?.precision || 0.1, config?.noiseLevel || 0.2);
    this.channels = config?.channels || 32;
    this.samplingRate = config?.samplingRate || 500; // Hz
    this.noiseFloor = config?.noiseFloor || 5; // μV
    this.artifactProbability = config?.artifactProbability || 0.01;

    // Initialize channel offsets
    for (let i = 0; i < this.channels; i++) {
      this.channelOffsets.push((Math.random() - 0.5) * 10);
    }
  }

  /**
   * Generate synthetic EEG signal
   */
  generateSignal(duration: number, eventTimestamps: number[] = []): Array<{
    timestamp: number;
    data: number[];
    events: string[];
  }> {
    const samples: Array<any> = [];
    const sampleInterval = 1000 / this.samplingRate;
    const numSamples = Math.ceil(duration / sampleInterval);

    for (let i = 0; i < numSamples; i++) {
      const timestamp = i * sampleInterval;
      const data: number[] = [];
      const events: string[] = [];

      // Check for events at this timestamp
      for (const eventTime of eventTimestamps) {
        if (Math.abs(timestamp - eventTime) < sampleInterval / 2) {
          events.push('stimulus');
        }
      }

      // Generate signal for each channel
      for (let ch = 0; ch < this.channels; ch++) {
        let signal = 0;

        // Alpha rhythm (8-12 Hz)
        signal += 10 * Math.sin(2 * Math.PI * 10 * timestamp / 1000 + this.channelOffsets[ch]);

        // Beta rhythm (13-30 Hz)
        signal += 5 * Math.sin(2 * Math.PI * 20 * timestamp / 1000 + this.channelOffsets[ch] * 2);

        // Gamma rhythm (30-100 Hz)
        signal += 2 * Math.sin(2 * Math.PI * 40 * timestamp / 1000 + this.channelOffsets[ch] * 3);

        // Event-related potential (if event occurred)
        if (events.length > 0) {
          const erpLatency = timestamp - eventTimestamps[eventTimestamps.indexOf(timestamp)];
          if (erpLatency >= 0 && erpLatency < 600) {
            // P300-like component
            if (erpLatency > 250 && erpLatency < 500) {
              signal += 15 * Math.exp(-(Math.pow(erpLatency - 300, 2) / 10000));
            }
            // N100-like component
            if (erpLatency > 80 && erpLatency < 150) {
              signal -= 8 * Math.exp(-(Math.pow(erpLatency - 100, 2) / 400));
            }
          }
        }

        // Add noise
        signal += this.gaussianNoise() * this.noiseFloor;

        // Add artifacts occasionally
        if (Math.random() < this.artifactProbability) {
          signal += (Math.random() - 0.5) * 100; // Large artifact
        }

        data.push(Math.round(signal * this.precision) / this.precision);
      }

      samples.push({
        timestamp: timestamp + this.simulateLatency(),
        data,
        events
      });
    }

    return samples;
  }

  /**
   * Generate specific ERP component
   */
  generateERP(
    component: 'N100' | 'P300' | 'N400' | 'MMN',
    amplitude: number = 10
  ): Array<{ timestamp: number; amplitude: number }> {
    const erp: Array<any> = [];
    const sampleInterval = 1000 / this.samplingRate;

    let peakLatency: number;
    let duration: number;
    let polarity: number;

    switch (component) {
      case 'N100':
        peakLatency = 100;
        duration = 100;
        polarity = -1;
        break;
      case 'P300':
        peakLatency = 300;
        duration = 200;
        polarity = 1;
        break;
      case 'N400':
        peakLatency = 400;
        duration = 200;
        polarity = -1;
        break;
      case 'MMN':
        peakLatency = 150;
        duration = 100;
        polarity = -1;
        break;
    }

    for (let t = 0; t < 1000; t += sampleInterval) {
      let value = 0;

      if (t > peakLatency - duration / 2 && t < peakLatency + duration / 2) {
        // Gaussian-shaped component
        value = amplitude * polarity * Math.exp(-(Math.pow(t - peakLatency, 2) / (2 * Math.pow(duration / 4, 2))));
      }

      erp.push({
        timestamp: t,
        amplitude: value + this.gaussianNoise() * this.noiseFloor * 0.1
      });
    }

    return erp;
  }

  private gaussianNoise(): number {
    const u1 = Math.random();
    const u2 = Math.random();
    return Math.sqrt(-2 * Math.log(u1)) * Math.cos(2 * Math.PI * u2);
  }
}

/**
 * Factory for creating virtual devices
 */
export class VirtualDeviceFactory {
  static createKeyboard(config?: Partial<VirtualKeyboard>): VirtualKeyboardDevice {
    return new VirtualKeyboardDevice(config);
  }

  static createMouse(config?: Partial<VirtualMouse>): VirtualMouseDevice {
    return new VirtualMouseDevice(config);
  }

  static createEyeTracker(config?: Partial<VirtualEyeTracker>): VirtualEyeTrackerDevice {
    return new VirtualEyeTrackerDevice(config);
  }

  static createEEG(config?: Partial<VirtualEEG>): VirtualEEGDevice {
    return new VirtualEEGDevice(config);
  }
}

