/**
 * Tests for HeadlessRunner
 */

import { describe, it, expect, beforeEach, vi } from 'vitest';
import { HeadlessRunner } from '../src/HeadlessRunner';
import { CognitiveModels } from '../src/CognitiveModels';
import type { HeadlessConfig, SimulationResults } from '../src/types';

describe('HeadlessRunner', () => {
  let config: HeadlessConfig;

  beforeEach(() => {
    config = {
      experiment: {} as any, // Mock experiment
      cognitiveModel: CognitiveModels.simpleRT,
      participants: 2,
      speedMultiplier: 100, // 100x speed for fast tests
      randomSeed: 12345,
      memoryBudget: 50 * 1024 * 1024 // 50MB
    };
  });

  describe('constructor', () => {
    it('should initialize with provided config', () => {
      const runner = new HeadlessRunner(config);
      expect(runner).toBeDefined();
      expect(runner.getMemoryUsage()).toBeDefined();
    });

    it('should use default memory budget if not specified', () => {
      delete config.memoryBudget;
      const runner = new HeadlessRunner(config);
      const memory = runner.getMemoryUsage();
      expect(memory.wasmMemoryLimit).toBe(100 * 1024 * 1024); // 100MB default
    });

    it('should initialize participants', () => {
      const runner = new HeadlessRunner(config);
      // Participants are initialized internally
      expect(runner).toBeDefined();
    });
  });

  describe('simulate', () => {
    it('should run complete simulation', async () => {
      const runner = new HeadlessRunner(config);
      const results = await runner.simulate();

      expect(results).toBeDefined();
      expect(results.participants).toHaveLength(2);
      expect(results.aggregateMetrics).toBeDefined();
      expect(results.performanceReport).toBeDefined();
    });

    it('should generate deterministic results with same seed', async () => {
      const runner1 = new HeadlessRunner(config);
      const runner2 = new HeadlessRunner(config);

      const results1 = await runner1.simulate();
      const results2 = await runner2.simulate();

      // Check that aggregate metrics are similar (not exact due to timing)
      expect(results1.aggregateMetrics.overallAccuracy).toBeCloseTo(
        results2.aggregateMetrics.overallAccuracy,
        1
      );
    });

    it('should respect memory budget', async () => {
      config.memoryBudget = 1024; // 1KB - very small
      const runner = new HeadlessRunner(config);

      // Should throw when memory exceeded
      await expect(runner.simulate()).rejects.toThrow('Memory budget exceeded');
    });
  });

  describe('simulateUntil', () => {
    it('should simulate until specified time', async () => {
      const runner = new HeadlessRunner(config);
      const targetTime = 10; // 10 seconds virtual time

      const state = await runner.simulateUntil(targetTime);

      expect(state).toBeDefined();
      expect(state.virtualTime).toBeGreaterThanOrEqual(targetTime);
      expect(state.participantState).toBeDefined();
    });

    it('should update performance metrics', async () => {
      const runner = new HeadlessRunner(config);

      const state = await runner.simulateUntil(5);

      expect(state.performanceMetrics.fps).toBeGreaterThan(0);
      expect(state.performanceMetrics.simulationSpeed).toBe(100);
    });
  });

  describe('getMemoryUsage', () => {
    it('should return memory metrics', () => {
      const runner = new HeadlessRunner(config);
      const memory = runner.getMemoryUsage();

      expect(memory).toHaveProperty('heapUsed');
      expect(memory).toHaveProperty('heapTotal');
      expect(memory).toHaveProperty('wasmMemoryUsed');
      expect(memory).toHaveProperty('wasmMemoryLimit');
      expect(memory).toHaveProperty('gcCount');
      expect(memory).toHaveProperty('lastGCDuration');
    });
  });

  describe('simulation results', () => {
    it('should include participant results', async () => {
      const runner = new HeadlessRunner(config);
      const results = await runner.simulate();

      expect(results.participants).toHaveLength(2);

      const participant = results.participants[0];
      expect(participant).toHaveProperty('participantId');
      expect(participant).toHaveProperty('trials');
      expect(participant).toHaveProperty('summary');
    });

    it('should calculate aggregate metrics', async () => {
      const runner = new HeadlessRunner(config);
      const results = await runner.simulate();

      const metrics = results.aggregateMetrics;
      expect(metrics).toHaveProperty('overallAccuracy');
      expect(metrics).toHaveProperty('overallMeanRT');
      expect(metrics).toHaveProperty('conditionEffects');
      expect(metrics).toHaveProperty('learningCurve');
      expect(metrics).toHaveProperty('fatigueEffects');
    });

    it('should generate performance report', async () => {
      const runner = new HeadlessRunner(config);
      const results = await runner.simulate();

      const report = results.performanceReport;
      expect(report).toHaveProperty('totalSimulationTime');
      expect(report).toHaveProperty('virtualTimeElapsed');
      expect(report).toHaveProperty('speedupFactor');
      expect(report.speedupFactor).toBeGreaterThan(1); // Should be faster than real-time
    });

    it('should export data in BIDS format', async () => {
      const runner = new HeadlessRunner(config);
      const results = await runner.simulate();

      expect(results.dataExport).toBeDefined();
      expect(Array.isArray(results.dataExport)).toBe(true);

      if (results.dataExport.length > 0) {
        const trial = results.dataExport[0];
        expect(trial).toHaveProperty('participant_id');
        expect(trial).toHaveProperty('trial');
        expect(trial).toHaveProperty('condition');
        expect(trial).toHaveProperty('rt');
        expect(trial).toHaveProperty('accuracy');
        expect(trial).toHaveProperty('onset');
        expect(trial).toHaveProperty('duration');
      }
    });
  });

  describe('cognitive model integration', () => {
    it('should use cognitive model for response generation', async () => {
      const mockModel = {
        reactionTime: vi.fn().mockReturnValue(400),
        accuracy: vi.fn().mockReturnValue(true),
        learningCurve: vi.fn().mockReturnValue(0.95)
      };

      config.cognitiveModel = mockModel;
      const runner = new HeadlessRunner(config);

      await runner.simulateUntil(1);

      // Model methods should be called during simulation
      expect(mockModel.reactionTime).toHaveBeenCalled();
      expect(mockModel.accuracy).toHaveBeenCalled();
      expect(mockModel.learningCurve).toHaveBeenCalled();
    });
  });

  describe('determinism', () => {
    it('should produce identical results with same seed', async () => {
      const config1 = { ...config, randomSeed: 42 };
      const config2 = { ...config, randomSeed: 42 };

      const runner1 = new HeadlessRunner(config1);
      const runner2 = new HeadlessRunner(config2);

      const state1 = await runner1.simulateUntil(5);
      const state2 = await runner2.simulateUntil(5);

      // Virtual time should be identical
      expect(state1.virtualTime).toBe(state2.virtualTime);
    });

    it('should produce different results with different seeds', async () => {
      const config1 = { ...config, randomSeed: 42 };
      const config2 = { ...config, randomSeed: 43 };

      const runner1 = new HeadlessRunner(config1);
      const runner2 = new HeadlessRunner(config2);

      const results1 = await runner1.simulate();
      const results2 = await runner2.simulate();

      // Results should differ
      expect(results1.aggregateMetrics.overallMeanRT).not.toBe(
        results2.aggregateMetrics.overallMeanRT
      );
    });
  });
});

