/**
 * Tests for Virtual Devices
 */

import { describe, it, expect, beforeEach } from 'vitest';
import {
  VirtualKeyboardDevice,
  VirtualMouseDevice,
  VirtualEyeTrackerDevice,
  VirtualEEGDevice,
  VirtualDeviceFactory
} from '../src/VirtualDevices';

describe('VirtualKeyboardDevice', () => {
  let keyboard: VirtualKeyboardDevice;

  beforeEach(() => {
    keyboard = new VirtualKeyboardDevice();
  });

  describe('simulateKeyPress', () => {
    it('should generate key press with latency', () => {
      const result = keyboard.simulateKeyPress('a', 1000);

      expect(result.key).toBe('a');
      expect(result.timestamp).toBeGreaterThan(1000);
      expect(result.latency).toBeGreaterThan(0);
    });

    it('should add variability to key press timing', () => {
      const presses = Array.from({ length: 10 }, (_, i) => 
        keyboard.simulateKeyPress('a', 1000 + i * 100)
      );

      const latencies = presses.map(p => p.latency);
      const uniqueLatencies = new Set(latencies);
      expect(uniqueLatencies.size).toBeGreaterThan(5);
    });

    it('should prevent double presses', () => {
      const press1 = keyboard.simulateKeyPress('a', 1000);
      const press2 = keyboard.simulateKeyPress('a', 1020); // Within threshold

      expect(press1.key).toBe('a');
      expect(press2.key).toBe(''); // Double press ignored
    });
  });

  describe('simulateKeyRelease', () => {
    it('should calculate key press duration', () => {
      keyboard.simulateKeyPress('a', 1000);
      const release = keyboard.simulateKeyRelease('a', 1200);

      expect(release.key).toBe('a');
      expect(release.duration).toBeCloseTo(200, -1);
    });
  });

  describe('getKeyStates', () => {
    it('should track key states', () => {
      keyboard.simulateKeyPress('a', 1000);
      keyboard.simulateKeyPress('b', 1100);

      const states = keyboard.getKeyStates();
      expect(states.get('a')).toBe(true);
      expect(states.get('b')).toBe(true);

      keyboard.simulateKeyRelease('a', 1200);
      const newStates = keyboard.getKeyStates();
      expect(newStates.get('a')).toBe(false);
    });
  });
});

describe('VirtualMouseDevice', () => {
  let mouse: VirtualMouseDevice;

  beforeEach(() => {
    mouse = new VirtualMouseDevice();
  });

  describe('simulateMovement', () => {
    it('should generate smooth movement path', () => {
      const path = mouse.simulateMovement(100, 100, 500);

      expect(path.length).toBeGreaterThan(10);
      // First point should be close to origin (with noise)
      expect(Math.abs(path[0].x)).toBeLessThan(3);
      expect(Math.abs(path[0].y)).toBeLessThan(3);
      expect(path[path.length - 1].x).toBeCloseTo(100, 0);
      expect(path[path.length - 1].y).toBeCloseTo(100, 0);
    });

    it('should add movement noise', () => {
      const path = mouse.simulateMovement(100, 0, 500);

      // Check that not all y coordinates are exactly 0
      const yVariation = path.some(p => Math.abs(p.y) > 0.1);
      expect(yVariation).toBe(true);
    });

    it('should respect precision', () => {
      const preciseMouse = new VirtualMouseDevice({ precision: 0.1 });
      const path = preciseMouse.simulateMovement(10.123, 20.456, 100);

      path.forEach(point => {
        // Check that values are rounded to precision
        const xRounded = Math.round(point.x / 0.1) * 0.1;
        const yRounded = Math.round(point.y / 0.1) * 0.1;
        expect(point.x).toBeCloseTo(xRounded, 5);
        expect(point.y).toBeCloseTo(yRounded, 5);
      });
    });
  });

  describe('simulateClick', () => {
    it('should generate click with latency', () => {
      const click = mouse.simulateClick(0, 1000); // Left button

      expect(click.button).toBe(0);
