/**
 * Tests for Virtual Devices
 */

import { describe, it, expect, beforeEach } from 'vitest';
import {
  VirtualKeyboardDevice,
  VirtualMouseDevice,
  VirtualEyeTrackerDevice,
  VirtualEEGDevice,
  VirtualDeviceFactory
} from '../src/VirtualDevices';

describe('VirtualKeyboardDevice', () => {
  let keyboard: VirtualKeyboardDevice;

  beforeEach(() => {
    keyboard = new VirtualKeyboardDevice();
  });

  describe('simulateKeyPress', () => {
    it('should generate key press with latency', () => {
      const result = keyboard.simulateKeyPress('a', 1000);

      expect(result.key).toBe('a');
      expect(result.timestamp).toBeGreaterThan(1000);
      expect(result.latency).toBeGreaterThan(0);
    });

    it('should add variability to key press timing', () => {
      const presses = Array.from({ length: 10 }, (_, i) => 
        keyboard.simulateKeyPress('a', 1000 + i * 100)
      );

      const latencies = presses.map(p => p.latency);
      const uniqueLatencies = new Set(latencies);
      expect(uniqueLatencies.size).toBeGreaterThan(5);
    });

    it('should prevent double presses', () => {
      const press1 = keyboard.simulateKeyPress('a', 1000);
      const press2 = keyboard.simulateKeyPress('a', 1020); // Within threshold

      expect(press1.key).toBe('a');
      expect(press2.key).toBe(''); // Double press ignored
    });
  });

  describe('simulateKeyRelease', () => {
    it('should calculate key press duration', () => {
      keyboard.simulateKeyPress('a', 1000);
      const release = keyboard.simulateKeyRelease('a', 1200);

      expect(release.key).toBe('a');
      expect(release.duration).toBeCloseTo(200, -1);
    });
  });

  describe('getKeyStates', () => {
    it('should track key states', () => {
      keyboard.simulateKeyPress('a', 1000);
      keyboard.simulateKeyPress('b', 1100);

      const states = keyboard.getKeyStates();
      expect(states.get('a')).toBe(true);
      expect(states.get('b')).toBe(true);

      keyboard.simulateKeyRelease('a', 1200);
      const newStates = keyboard.getKeyStates();
      expect(newStates.get('a')).toBe(false);
    });
  });
});

describe('VirtualMouseDevice', () => {
  let mouse: VirtualMouseDevice;

  beforeEach(() => {
    mouse = new VirtualMouseDevice();
  });

  describe('simulateMovement', () => {
    it('should generate smooth movement path', () => {
      const path = mouse.simulateMovement(100, 100, 500);

      expect(path.length).toBeGreaterThan(10);
      // First point should be close to origin (with noise)
      expect(Math.abs(path[0].x)).toBeLessThan(3);
      expect(Math.abs(path[0].y)).toBeLessThan(3);
      // Last point should be at or very close to target (allowing for rounding)
      expect(path[path.length - 1].x).toBeCloseTo(100, 1);
      expect(path[path.length - 1].y).toBeCloseTo(100, 1);
    });

    it('should add movement noise', () => {
      const path = mouse.simulateMovement(100, 0, 500);

      // Check that not all y coordinates are exactly 0
      const yVariation = path.some(p => Math.abs(p.y) > 0.1);
      expect(yVariation).toBe(true);
    });

    it('should respect precision', () => {
      const preciseMouse = new VirtualMouseDevice({ precision: 0.1 });
      const path = preciseMouse.simulateMovement(10.123, 20.456, 100);

      path.forEach(point => {
        // Check that values are rounded to precision
        const xRounded = Math.round(point.x / 0.1) * 0.1;
        const yRounded = Math.round(point.y / 0.1) * 0.1;
        expect(point.x).toBeCloseTo(xRounded, 5);
        expect(point.y).toBeCloseTo(yRounded, 5);
      });
    });
  });

  describe('simulateClick', () => {
    it('should generate click with latency', () => {
      const click = mouse.simulateClick(0, 1000); // Left button

      expect(click.button).toBe(0);
      expect(click.timestamp).toBeGreaterThan(1000);
      expect(click.latency).toBeGreaterThan(0);
    });
  });

  describe('simulateScroll', () => {
    it('should apply scroll sensitivity', () => {
      const sensitiveMouse = new VirtualMouseDevice({ scrollSensitivity: 5 });
      const scroll = sensitiveMouse.simulateScroll(10, 1000);

      expect(Math.abs(scroll.deltaY)).toBeGreaterThan(10);
      expect(scroll.timestamp).toBeGreaterThan(1000);
    });
  });
});

describe('VirtualEyeTrackerDevice', () => {
  let eyeTracker: VirtualEyeTrackerDevice;

  beforeEach(() => {
    eyeTracker = new VirtualEyeTrackerDevice();
  });

  describe('simulateGazePath', () => {
    it('should generate saccade and fixation', () => {
      const path = eyeTracker.simulateGazePath(0, 0, 100, 100);

      expect(path.length).toBeGreaterThan(0);

      const saccadeStart = path.find(p => p.event === 'saccade_start');
      const saccadeEnd = path.find(p => p.event === 'saccade_end');
      const fixationStart = path.find(p => p.event === 'fixation_start');

      expect(saccadeStart).toBeDefined();
      expect(saccadeEnd).toBeDefined();
      expect(fixationStart).toBeDefined();
    });

    it('should include pupil size data', () => {
      const path = eyeTracker.simulateGazePath(0, 0, 50, 50);

      path.forEach(sample => {
        expect(sample.pupilSize).toBeGreaterThan(0);
      });
    });

    it('should add spatial noise', () => {
      const path = eyeTracker.simulateGazePath(0, 0, 100, 0, false); // No saccade

      const xValues = path.map(p => p.x);
      const hasVariation = xValues.some((x, i) => 
        i > 0 && Math.abs(x - xValues[i - 1]) > 0.01
      );

      expect(hasVariation).toBe(true);
    });
  });

  describe('simulateBlink', () => {
    it('should generate blink with NaN coordinates', () => {
      const blink = eyeTracker.simulateBlink(1000);

      expect(blink.length).toBeGreaterThan(0);

      blink.forEach(sample => {
        expect(Number.isNaN(sample.x)).toBe(true);
        expect(Number.isNaN(sample.y)).toBe(true);
        expect(sample.pupilSize).toBe(0);
      });

      const blinkStart = blink.find(p => p.event === 'blink_start');
      const blinkEnd = blink.find(p => p.event === 'blink_end');

      expect(blinkStart).toBeDefined();
      expect(blinkEnd).toBeDefined();
    });
  });

  describe('simulateSmoothPursuit', () => {
    it('should follow moving target', () => {
      const targetPath = [
        { x: 0, y: 0, timestamp: 0 },
        { x: 50, y: 0, timestamp: 500 },
        { x: 100, y: 0, timestamp: 1000 }
      ];

      const pursuit = eyeTracker.simulateSmoothPursuit(targetPath);

      expect(pursuit.length).toBe(targetPath.length);
      expect(pursuit[0].event).toBe('smooth_pursuit_start');

      // Should roughly follow target (with some overshoot)
      // The final x position will be slightly over 100 due to overshoot
      expect(pursuit[pursuit.length - 1].x).toBeGreaterThan(100);
      expect(pursuit[pursuit.length - 1].x).toBeLessThan(110); // But not too much overshoot
    });
  });
});

describe('VirtualEEGDevice', () => {
  let eeg: VirtualEEGDevice;

  beforeEach(() => {
    eeg = new VirtualEEGDevice();
  });

  describe('generateSignal', () => {
    it('should generate multi-channel EEG data', () => {
      const signal = eeg.generateSignal(1000); // 1 second

      expect(signal.length).toBeGreaterThan(0);

      signal.forEach(sample => {
        expect(sample.data).toHaveLength(32); // Default 32 channels
        expect(sample.timestamp).toBeDefined();
        expect(Array.isArray(sample.events)).toBe(true);
      });
    });

    it('should mark stimulus events', () => {
      const events = [100, 300, 500]; // Event timestamps
      const signal = eeg.generateSignal(1000, events);

      const samplesWithEvents = signal.filter(s => s.events.length > 0);
      expect(samplesWithEvents.length).toBeGreaterThan(0);
    });

    it('should respect sampling rate', () => {
      const customEEG = new VirtualEEGDevice({ samplingRate: 1000 });
      const signal = customEEG.generateSignal(100); // 100ms

      expect(signal.length).toBeCloseTo(100, 5); // ~100 samples at 1000Hz
    });
  });

  describe('generateERP', () => {
    it('should generate N100 component', () => {
      const n100 = eeg.generateERP('N100', 10);

      const peakSample = n100.find(s => 
        s.timestamp >= 90 && s.timestamp <= 110
      );

      expect(peakSample).toBeDefined();
      expect(peakSample!.amplitude).toBeLessThan(0); // Negative component
    });

    it('should generate P300 component', () => {
      const p300 = eeg.generateERP('P300', 15);

      const peakSample = p300.find(s => 
        s.timestamp >= 250 && s.timestamp <= 350
      );

      expect(peakSample).toBeDefined();
      expect(peakSample!.amplitude).toBeGreaterThan(0); // Positive component
    });

    it('should scale amplitude', () => {
      const smallERP = eeg.generateERP('N400', 5);
      const largeERP = eeg.generateERP('N400', 20);

      const smallPeak = Math.min(...smallERP.map(s => s.amplitude));
      const largePeak = Math.min(...largeERP.map(s => s.amplitude));

      expect(Math.abs(largePeak)).toBeGreaterThan(Math.abs(smallPeak));
    });
  });
});

describe('VirtualDeviceFactory', () => {
  it('should create keyboard device', () => {
    const keyboard = VirtualDeviceFactory.createKeyboard();
    expect(keyboard).toBeInstanceOf(VirtualKeyboardDevice);
  });

  it('should create mouse device', () => {
    const mouse = VirtualDeviceFactory.createMouse();
    expect(mouse).toBeInstanceOf(VirtualMouseDevice);
  });

  it('should create eye tracker device', () => {
    const eyeTracker = VirtualDeviceFactory.createEyeTracker();
    expect(eyeTracker).toBeInstanceOf(VirtualEyeTrackerDevice);
  });

  it('should create EEG device', () => {
    const eeg = VirtualDeviceFactory.createEEG();
    expect(eeg).toBeInstanceOf(VirtualEEGDevice);
  });

  it('should accept configuration', () => {
    const config = { latency: 20, precision: 5 };
    const keyboard = VirtualDeviceFactory.createKeyboard(config);

    expect(keyboard.latency).toBe(20);
    expect(keyboard.precision).toBe(5);
  });
});

