/**
 * Tests for Cognitive Models
 */

import { describe, it, expect, beforeEach } from 'vitest';
import {
  SimpleRTCognitiveModel,
  StroopCognitiveModel,
  NBackCognitiveModel,
  VisualSearchCognitiveModel,
  CognitiveModelFactory,
  CognitiveModels
} from '../src/CognitiveModels';

describe('SimpleRTCognitiveModel', () => {
  let model: SimpleRTCognitiveModel;

  beforeEach(() => {
    model = new SimpleRTCognitiveModel();
  });

  describe('reactionTime', () => {
    it('should generate reaction times above minimum', () => {
      const rt = model.reactionTime({}, 0.5);
      expect(rt).toBeGreaterThanOrEqual(150); // Minimum RT
    });

    it('should increase RT with difficulty', () => {
      const easyRT = model.reactionTime({}, 0);
      const hardRT = model.reactionTime({}, 1);
      expect(hardRT).toBeGreaterThan(easyRT);
    });

    it('should add variability to RT', () => {
      const rts = Array.from({ length: 100 }, () => model.reactionTime({}, 0.5));
      const uniqueRTs = new Set(rts);
      expect(uniqueRTs.size).toBeGreaterThan(50); // Should have variation
    });
  });

  describe('accuracy', () => {
    it('should decrease accuracy with fatigue', () => {
      const accuracyFresh = Array.from({ length: 1000 }, () => 
        model.accuracy({}, 0)
      ).filter(Boolean).length / 1000;

      const accuracyFatigued = Array.from({ length: 1000 }, () => 
        model.accuracy({}, 0.8)
      ).filter(Boolean).length / 1000;

      expect(accuracyFatigued).toBeLessThan(accuracyFresh);
    });

    it('should maintain base error rate', () => {
      const trials = 10000;
      const correct = Array.from({ length: trials }, () => 
        model.accuracy({}, 0)
      ).filter(Boolean).length;

      const accuracy = correct / trials;
      expect(accuracy).toBeCloseTo(1 - model.errorRate, 1);
    });
  });

  describe('learningCurve', () => {
    it('should show improvement over trials', () => {
      const early = model.learningCurve(1, 'default');
      const late = model.learningCurve(100, 'default');
      expect(early).toBeGreaterThan(late); // Lower values = better performance
    });

    it('should plateau with many trials', () => {
      const trial100 = model.learningCurve(100, 'default');
      const trial1000 = model.learningCurve(1000, 'default');
      expect(Math.abs(trial100 - trial1000)).toBeLessThan(0.01);
    });
  });
});

describe('StroopCognitiveModel', () => {
  let model: StroopCognitiveModel;

  beforeEach(() => {
    model = new StroopCognitiveModel();
  });

  describe('reactionTime', () => {
    it('should have faster RT for congruent trials', () => {
      const congruentStimulus = { condition: 'congruent' };
      const incongruentStimulus = { condition: 'incongruent' };

      const congruentRT = model.reactionTime(congruentStimulus, 0.5);
      const incongruentRT = model.reactionTime(incongruentStimulus, 0.5);

      expect(congruentRT).toBeLessThan(incongruentRT);
    });

    it('should show conflict adaptation (Gratton effect)', () => {
      const incongruent = { condition: 'incongruent' };

      // First incongruent trial
      const rt1 = model.reactionTime(incongruent, 0.5);

      // Second incongruent trial (should be faster due to adaptation)
      const rt2 = model.reactionTime(incongruent, 0.5);

      expect(rt2).toBeLessThan(rt1);
    });
  });

  describe('accuracy', () => {
    it('should have higher accuracy for congruent trials', () => {
      const congruent = { condition: 'congruent' };
      const incongruent = { condition: 'incongruent' };

      const congruentAcc = Array.from({ length: 1000 }, () => 
        model.accuracy(congruent, 0)
      ).filter(Boolean).length / 1000;

      const incongruentAcc = Array.from({ length: 1000 }, () => 
        model.accuracy(incongruent, 0)
      ).filter(Boolean).length / 1000;

      expect(congruentAcc).toBeGreaterThan(incongruentAcc);
    });

    it('should show greater fatigue effect on incongruent trials', () => {
      const incongruent = { condition: 'incongruent' };

      const freshAcc = Array.from({ length: 1000 }, () => 
        model.accuracy(incongruent, 0)
      ).filter(Boolean).length / 1000;

      const fatiguedAcc = Array.from({ length: 1000 }, () => 
        model.accuracy(incongruent, 0.8)
      ).filter(Boolean).length / 1000;

      const accuracyDrop = freshAcc - fatiguedAcc;
      expect(accuracyDrop).toBeGreaterThan(0.1);
    });
  });
});

describe('NBackCognitiveModel', () => {
  let model: NBackCognitiveModel;

  beforeEach(() => {
    model = new NBackCognitiveModel();
  });

  describe('reactionTime', () => {
